def load_contract(name):
    """Load deployed contract from JSON (local or global dir)."""
    path = os.path.join(DEPLOY_DIR, f"{name}.json")
    if not os.path.exists(path):
        path = os.path.join(GLOBAL_DEPLOY_DIR, f"{name}.json")
    with open(path) as f:
        info = json.load(f)
    return w3.eth.contract(
        address=Web3.to_checksum_address(info["address"]),
        abi=info["abi"],
    )

def tx(fn_call, gas=1000000):
    """Execute a transaction and return receipt."""
    tx_hash = fn_call.transact({"from": DEPLOYER, "gas": gas})
    return w3.eth.wait_for_transaction_receipt(tx_hash, timeout=30)

def test_spend_insufficient():
    """Spending more than balance should revert."""
    tx(tm.functions.mintDailyECT(AGENT_CEO, 10))
    try:
        tx(tm.functions.spendECT(AGENT_CEO, 100, Web3.keccak(text="too-much")))
        assert False, "Should have reverted"
    except Exception as e:
        assert "Insufficient ECT" in str(e) or "revert" in str(e).lower()
        print(f"  Correctly reverted: insufficient ECT")

def test_trigger_reward():
    """Trigger reward if quality score is high enough."""
    # Get score first
    score, window, _, _ = dq.functions.calculateQualityScore(AGENT_CEO).call()
    print(f"  Current score: {score}, window: {window}")

    # Get RST before
    _, rst_before = tm.functions.getBalances(AGENT_CEO).call()

    try:
        receipt = tx(dq.functions.triggerReward(AGENT_CEO))
        assert receipt["status"] == 1

        _, rst_after = tm.functions.getBalances(AGENT_CEO).call()
        print(f"  RST: {rst_before} → {rst_after}")

        logs = dq.events.QualityScoreCalculated().process_receipt(receipt)
        if logs:
            print(f"  Score event: score={logs[0]['args']['score']}")

        reward_logs = dq.events.RewardTriggered().process_receipt(receipt)
        if reward_logs:
            print(f"  Reward triggered! amount={reward_logs[0]['args']['rstAmount']}")
        else:
            print(f"  No reward (score {score} <= threshold)")
    except Exception as e:
        if "Cooldown" in str(e):
            print(f"  Cooldown not elapsed (expected in rapid testing)")
        else:
            raise

