def __init__(self):
        self._clients = {}
        self._lock = threading.Lock()

def _connect(self, hostname, ip):
        client = paramiko.SSHClient()
        client.set_missing_host_key_policy(paramiko.AutoAddPolicy())
        try:
            client.connect(ip, username="mhuraibi", key_filename=SSH_KEY,
                           timeout=5, banner_timeout=5)
            return client
        except Exception as e:
            log.debug("SSH to %s (%s) failed: %s", hostname, ip, e)
            return None

def run(self, hostname, cmd, timeout=5):
        """Run command on remote node, return stdout string or None."""
        info = NODES.get(hostname)
        if not info or not info["ssh"]:
            return None

        with self._lock:
            client = self._clients.get(hostname)
            if client and not client.get_transport():
                client = None
            if client:
                transport = client.get_transport()
                if not transport or not transport.is_active():
                    client = None

            if not client:
                client = self._connect(hostname, info["ip"])
                if client:
                    self._clients[hostname] = client
                else:
                    self._clients.pop(hostname, None)
                    return None

        try:
            _, stdout, _ = client.exec_command(cmd, timeout=timeout)
            return stdout.read().decode("utf-8", errors="replace").strip()
        except Exception as e:
            log.debug("SSH exec on %s failed: %s", hostname, e)
            with self._lock:
                self._clients.pop(hostname, None)
            return None

def run_local(self, cmd, timeout=5):
        """Run command locally."""
        try:
            r = subprocess.run(cmd, shell=True, capture_output=True,
                               text=True, timeout=timeout)
            return r.stdout.strip()
        except Exception:
            return None

