def _parse_temp(raw):
    """Parse vcgencmd output: temp=43.3'C -> 43.3"""
    if not raw:
        return None
    try:
        return float(raw.split("=")[1].split("'")[0])
    except (IndexError, ValueError):
        return None

def _parse_mem(raw):
    """Parse free -m output -> (total, used, available)."""
    if not raw:
        return None, None, None
    try:
        lines = raw.strip().split("\n")
        parts = lines[1].split()
        return int(parts[1]), int(parts[2]), int(parts[6])
    except (IndexError, ValueError):
        return None, None, None

def _parse_disk(raw):
    """Parse df -h / -> (size, used, avail, pct)."""
    if not raw:
        return None, None, None, None
    try:
        parts = raw.strip().split("\n")[-1].split()
        return parts[1], parts[2], parts[3], parts[4]
    except (IndexError, ValueError):
        return None, None, None, None

def _parse_load(raw):
    """Parse /proc/loadavg -> (1m, 5m, 15m)."""
    if not raw:
        return None, None, None
    try:
        parts = raw.strip().split()
        return float(parts[0]), float(parts[1]), float(parts[2])
    except (IndexError, ValueError):
        return None, None, None

def _parse_netdev(raw, iface="eth0"):
    """Parse /proc/net/dev -> (rx_bytes, tx_bytes)."""
    if not raw:
        return 0, 0
    for line in raw.strip().split("\n"):
        if iface in line:
            parts = line.split()
            try:
                return int(parts[1]), int(parts[9])
            except (IndexError, ValueError):
                return 0, 0
    return 0, 0

def collect_system():
    """Collect system stats for all nodes in parallel."""
    results = {}
    threads = []

    def _worker(name, info):
        results[name] = collect_system_one(name, info)

    for name, info in NODES.items():
        t = threading.Thread(target=_worker, args=(name, info))
        threads.append(t)
        t.start()

    for t in threads:
        t.join(timeout=10)

    # Check blockchain sync as alert
    try:
        bc = collect_blockchain_quick()
        if bc and not bc.get("consensus"):
            for name in results:
                results[name].setdefault("alerts", []).append("CHAIN DESYNC")
    except Exception:
        pass

    return results

