function setWsStatus(state) {
    const dot = document.getElementById("ws-dot");
    const text = document.getElementById("ws-text");
    if (state === "connected") {
        dot.className = "status-dot ok";
        text.textContent = "Live";
    } else if (state === "reconnecting") {
        dot.className = "status-dot warn";
        text.textContent = "Reconnecting...";
    } else {
        dot.className = "status-dot error";
        text.textContent = "Disconnected";
    }
}

// ── Global status ──────────────────────────────────────────────
let systemOk = false;
let chainOk = false;
let ipfsOk = false;

function updateGlobalStatus() {
    const badge = document.getElementById("global-status");
    const dot = document.getElementById("global-dot");
    const text = document.getElementById("global-text");

    if (systemOk && chainOk && ipfsOk) {
        badge.className = "status-badge ok";
        dot.className = "status-dot ok";
        text.textContent = "All Systems Operational";
    } else if (chainOk || ipfsOk) {
        badge.className = "status-badge warn";
        dot.className = "status-dot warn";
        const issues = [];
        if (!chainOk) issues.push("Chain");
        if (!ipfsOk) issues.push("IPFS");
        if (!systemOk) issues.push("Nodes");
        text.textContent = issues.join(", ") + " degraded";
    } else {
        badge.className = "status-badge error";
        dot.className = "status-dot error";
        text.textContent = "Systems Offline";
    }
}

