async def run_single(session, url, messages, headers=None, timeout=60):
    """Run a single inference request, return (latency_s, response_len, tokens)."""
    payload = {"messages": messages, "max_tokens": MAX_TOKENS, "temperature": 0.7}

    start = time.monotonic()
    try:
        async with session.post(
            url, json=payload,
            headers=headers or {"Content-Type": "application/json"},
            timeout=aiohttp.ClientTimeout(total=timeout),
        ) as resp:
            if resp.status != 200:
                body = await resp.text()
                return None, f"HTTP {resp.status}: {body[:100]}"
            data = await resp.json()
            latency = time.monotonic() - start
            text = data["choices"][0]["message"]["content"]
            # Rough token count: words * 1.3
            tokens = len(text.split()) * 1.3
            return {
                "latency": latency,
                "response_len": len(text),
                "tokens": tokens,
                "tokens_per_sec": tokens / latency if latency > 0 else 0,
            }, None
    except Exception as e:
        return None, str(e)

