def decode_mode(mode):
    if mode == 0:
        return "F_OK"
    flags = []
    for bit, name in sorted(MODE_FLAGS.items()):
        if bit > 0 and mode & bit:
            flags.append(name)
    return "|".join(flags) if flags else f"0x{mode:x}"

def close(self):
        if self._file:
            self._file.close()

def add(self, event_dict):
        self.events.append(event_dict)
        ts = event_dict["ts"]
        if self.first_ts == 0:
            self.first_ts = ts
        self.last_ts = ts

def start(self):
        self._thread = threading.Thread(target=self._run, daemon=True, name="bc-sender")
        self._thread.start()

def _run(self):
        self.log.info("Sender thread started")
        while self._running or self._queue:
            self._event.wait(timeout=0.05)
            self._event.clear()
            if self._running:
                self._drain()
            else:
                # Drain remaining but cap at 10 to avoid long shutdown
                self._drain(max_batches=10)
        self.log.info("Sender thread stopped (sent=%d errors=%d)",
                      self.total_batches_sent, self.total_tx_errors)

def _drain(self, max_batches=0):
        sent = 0
        while True:
            with self._lock:
                if not self._queue:
                    return
                batch = self._queue.popleft()
            self._send_batch(batch)
            sent += 1
            if max_batches and sent >= max_batches:
                return

def _check_timer_flush(self):
        now = time.monotonic()
        if now - self._last_flush >= self._max_interval:
            with self._batch_lock:
                if self._current_batch.events:
                    self._flush_batch_locked()

def _flush_batch(self):
        with self._batch_lock:
            if self._current_batch and self._current_batch.events:
                self._flush_batch_locked()

def _new_batch(self):
        self._batch_counter += 1
        self._current_batch = Batch(self._batch_counter)

def decode_mode(mode):
    """Decode access mode bitmask to human-readable string."""
    if mode == 0:
        return "F_OK"
    flags = []
    for bit, name in sorted(MODE_FLAGS.items()):
        if bit > 0 and mode & bit:
            flags.append(name)
    return "|".join(flags) if flags else f"0x{mode:x}"

def _print_header(self):
        info = {
            "event": "monitor_start",
            "pid_filter": self.pid_filter if self.pid_filter > 0 else "all",
            "output": self.output_path or "stdout",
            "arch": "aarch64",
            "kernel": os.uname().release,
            "syscall": "faccessat (ARM64 has no native access())",
        }
        if not self.quiet:
            print(json.dumps(info, separators=(",", ":")), flush=True)

def _cleanup(self):
        elapsed = (time.monotonic_ns() - self.start_time) / 1e9
        summary = {
            "event": "monitor_stop",
            "total_events": self.event_count,
            "elapsed_seconds": round(elapsed, 2),
            "events_per_second": round(self.event_count / elapsed, 1) if elapsed > 0 else 0,
        }
        line = json.dumps(summary, separators=(",", ":"))
        if not self.quiet:
            print(line, flush=True)
        if self.output_file:
            self.output_file.write(line + "\n")
            self.output_file.close()

