def load_csv(path, latency_col="latency_ns"):
    """Load CSV, return dict of scenario → list of latencies (ns)."""
    scenarios = {}
    with open(path) as f:
        reader = csv.DictReader(f)
        for row in reader:
            if row.get("scenario", "").startswith("#"):
                continue
            scenario = row["scenario"]
            try:
                lat = int(row[latency_col])
            except (ValueError, KeyError):
                continue
            scenarios.setdefault(scenario, []).append(lat)
    return scenarios

def load_blockchain_csv(path):
    """Load blockchain CSV, return scenario → {access_ns, chain_ns, total_ns}."""
    scenarios = {}
    with open(path) as f:
        reader = csv.DictReader(f)
        for row in reader:
            scenario = row["scenario"]
            entry = scenarios.setdefault(scenario, {
                "access_ns": [], "chain_ns": [], "total_ns": [],
                "gas": [],
            })
            try:
                entry["access_ns"].append(int(row["access_latency_ns"]))
                entry["chain_ns"].append(int(row["chain_latency_ns"]))
                entry["total_ns"].append(int(row["total_latency_ns"]))
                entry["gas"].append(int(row["gas_used"]))
            except (ValueError, KeyError):
                continue
    return scenarios

