def _load_chunk_registry(self):
        """Load all chunk assignments from manifests."""
        self._chunk_registry.clear()
        if not MANIFEST_DIR.exists():
            return

        for mf in MANIFEST_DIR.glob("*.json"):
            try:
                with open(mf) as f:
                    manifest = json.load(f)
                chunk_cids = manifest.get("chunk_cids", [])
                chunk_nodes = manifest.get("chunk_nodes", [])
                for i, cid in enumerate(chunk_cids):
                    nodes = chunk_nodes[i] if i < len(chunk_nodes) else []
                    self._chunk_registry.append({
                        "cid": cid,
                        "cid_hash": hashlib.sha256(cid.encode()).digest(),
                        "nodes": nodes,
                        "file_id": manifest.get("file_id", ""),
                    })
            except Exception as e:
                log.warning("Failed to load manifest %s: %s", mf, e)

def _get_chunk_size(self, cid: str) -> int:
        """Get actual chunk size from any reachable IPFS node."""
        for name, api in IPFS_NODES.items():
            try:
                # Use object/stat to get size without downloading
                r = requests.post(
                    f"{api}/object/stat",
                    params={"arg": cid},
                    timeout=10,
                )
                if r.status_code == 200:
                    return r.json().get("CumulativeSize", 0)
            except Exception:
                continue
        # Fallback: fetch and measure
        for name, api in IPFS_NODES.items():
            try:
                r = requests.post(f"{api}/cat", params={"arg": cid}, timeout=30)
                if r.status_code == 200:
                    return len(r.content)
            except Exception:
                continue
        return 0

def _fetch_chunk_bytes(self, cid: str, offset: int, length: int) -> bytes:
        """Independently fetch chunk bytes for verification."""
        for name, api in IPFS_NODES.items():
            try:
                r = requests.post(f"{api}/cat", params={"arg": cid}, timeout=30)
                if r.status_code == 200:
                    data = r.content
                    if offset + length <= len(data):
                        return data[offset:offset + length]
            except Exception:
                continue
        raise RuntimeError(f"Cannot fetch chunk {cid[:16]}... from any node")

def select_target(self) -> dict:
        """Select a random node + chunk for the next challenge."""
        if not self._chunk_registry:
            self._load_chunk_registry()
        if not self._chunk_registry:
            raise RuntimeError("No chunks registered — nothing to challenge")

        # Pick a random chunk entry
        entry = random.choice(self._chunk_registry)

        # Pick a random node that claims to store this chunk
        if entry["nodes"]:
            node_name = random.choice(entry["nodes"])
        else:
            node_name = random.choice(list(IPFS_NODES.keys()))

        node_addr = NODE_ADDRESSES.get(node_name, DEPLOYER)
        return {
            "node_name": node_name,
            "node_address": node_addr,
            "cid": entry["cid"],
            "cid_hash": entry["cid_hash"],
            "file_id": entry["file_id"],
        }

def get_stats(self) -> dict:
        """Get statistics for all known nodes."""
        stats = {}
        for name, addr in NODE_ADDRESSES.items():
            try:
                s = self.contract.functions.getNodeStats(
                    Web3.to_checksum_address(addr)
                ).call()
                total, success, failed, expired, last_time, avg_ms = s

                success_rate = self.contract.functions.getNodeSuccessRate(
                    Web3.to_checksum_address(addr)
                ).call()

                stats[name] = {
                    "address": addr,
                    "total_challenges": total,
                    "successful": success,
                    "failed": failed,
                    "expired": expired,
                    "success_rate_pct": success_rate,
                    "avg_response_ms": avg_ms,
                    "last_challenge": last_time,
                    "healthy": success_rate >= 90,
                }
            except Exception as e:
                stats[name] = {"error": str(e)}

        return stats

def get_dashboard_json(self) -> dict:
        """Generate dashboard-ready JSON for the Storage Proof Health panel."""
        stats = self.get_stats()
        challenge_count = self.contract.functions.challengeCount().call()

        # Collect recent challenges
        recent = []
        start = max(0, challenge_count - 10)
        for i in range(start, challenge_count):
            try:
                c = self.contract.functions.getChallenge(i).call()
                node, cid_hash, offset, deadline, state, issued, responded, size = c
                recent.append({
                    "id": i,
                    "state": ["Pending", "Passed", "Failed", "Expired"][state],
                    "issued": issued,
                    "responded": responded,
                    "response_time_s": responded - issued if responded > 0 else None,
                })
            except Exception:
                pass

        # Alerts
        alerts = []
        for name, s in stats.items():
            if isinstance(s, dict) and s.get("success_rate_pct", 100) < 90:
                alerts.append({
                    "node": name,
                    "type": "low_success_rate",
                    "value": s["success_rate_pct"],
                    "message": f"{name} success rate {s['success_rate_pct']}% (below 90% threshold)",
                })

        return {
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "panel": "Storage Proof Health",
            "total_challenges": challenge_count,
            "nodes": stats,
            "recent_challenges": recent,
            "alerts": alerts,
        }

