def check_node_health() -> dict:
    """Ping each IPFS node. Returns {node_name: {"online": bool, "latency_ms": float}}."""
    results = {}
    for name, api in IPFS_NODES.items():
        try:
            t0 = time.monotonic()
            r = requests.post(f"{api}/id", timeout=5)
            latency = (time.monotonic() - t0) * 1000
            if r.status_code == 200:
                results[name] = {"online": True, "latency_ms": latency}
            else:
                results[name] = {"online": False, "latency_ms": 0}
        except Exception:
            results[name] = {"online": False, "latency_ms": 0}
    return results

def find_affected_manifests(offline_nodes: list) -> list:
    """Find all manifests that have chunks on offline nodes."""
    affected = []
    if not MANIFEST_DIR.exists():
        return affected

    for manifest_file in MANIFEST_DIR.glob("*.json"):
        try:
            with open(manifest_file) as f:
                manifest = json.load(f)
            chunk_nodes = manifest.get("chunk_nodes", [])
            for i, nodes in enumerate(chunk_nodes):
                for node in nodes:
                    if node in offline_nodes:
                        affected.append({
                            "file_id": manifest.get("file_id", manifest_file.stem),
                            "manifest": manifest,
                            "manifest_file": str(manifest_file),
                        })
                        break
                else:
                    continue
                break
        except Exception as e:
            log.warning("Failed to read manifest %s: %s", manifest_file, e)

    return affected

def run_check():
    """Execute one health check + rebalance cycle."""
    log.info("=" * 50)
    log.info("Chunk Monitor Check — %s", datetime.now(timezone.utc).isoformat())

    state = load_state()
    now = time.time()

    # Step 1: Check node health
    health = check_node_health()
    healthy_nodes = []
    offline_nodes = []
    newly_offline = []

    for name, status in health.items():
        if status["online"]:
            healthy_nodes.append(name)
            # Clear offline timer
            if name in state["node_status"]:
                if not state["node_status"][name].get("online", True):
                    log.info("  %s: RECOVERED (was offline)", name)
                state["node_status"][name] = {"online": True, "last_seen": now}
            else:
                state["node_status"][name] = {"online": True, "last_seen": now}
            log.info("  %s: ONLINE (%.0fms)", name, status["latency_ms"])
        else:
            offline_nodes.append(name)
            prev = state["node_status"].get(name, {})
            if prev.get("online", True):
                # Just went offline
                state["node_status"][name] = {
                    "online": False,
                    "offline_since": now,
                    "last_seen": prev.get("last_seen", now),
                }
                log.warning("  %s: OFFLINE (just detected)", name)
            else:
                offline_since = prev.get("offline_since", now)
                duration = now - offline_since
                log.warning("  %s: OFFLINE (%.0f seconds)", name, duration)
                if duration >= OFFLINE_THRESHOLD:
                    newly_offline.append(name)

    save_state(state)

    if not offline_nodes:
        log.info("All nodes healthy. No action needed.")
        return

    if not newly_offline:
        log.info(
            "%d nodes offline but under %ds threshold. Monitoring.",
            len(offline_nodes), OFFLINE_THRESHOLD,
        )
