def run_daemon():
    """Run as a daemon, checking every CHECK_INTERVAL seconds."""
    log.info("Chunk Monitor Daemon starting (interval=%ds, threshold=%ds)", CHECK_INTERVAL, OFFLINE_THRESHOLD)
    while True:
        try:
            run_check()
        except Exception as e:
            log.error("Check failed: %s", e, exc_info=True)
        time.sleep(CHECK_INTERVAL)

