def detect_node_name() -> str:
    """Detect which node we're running on by checking local IPFS."""
    import socket
    hostname = socket.gethostname().lower()
    for name in IPFS_NODES:
        if name.replace("-", "") in hostname.replace("-", ""):
            return name
    # Fallback: check which IPFS API responds on localhost
    try:
        r = requests.post("http://127.0.0.1:5001/api/v0/id", timeout=2)
        if r.status_code == 200:
            return "nexus-admin"  # local IPFS
    except Exception:
        pass
    return "nexus-admin"

def _load_cid_cache(self):
        """Build reverse lookup from cid_hash → CID from manifest files."""
        for mf in MANIFEST_DIR.glob("*.json"):
            try:
                with open(mf) as f:
                    manifest = json.load(f)
                for cid in manifest.get("chunk_cids", []):
                    cid_hash = hashlib.sha256(cid.encode()).digest()
                    self._cid_cache[cid_hash.hex()] = cid
            except Exception:
                pass
        self.log.info("CID cache loaded: %d entries", len(self._cid_cache))

def _resolve_cid(self, cid_hash_bytes: bytes) -> str:
        """Resolve a CID hash (bytes32) to the actual CID string."""
        hex_key = cid_hash_bytes.hex()
        if hex_key in self._cid_cache:
            return self._cid_cache[hex_key]

        # Reload manifests in case new files were uploaded
        self._load_cid_cache()
        if hex_key in self._cid_cache:
            return self._cid_cache[hex_key]

        raise ValueError(f"Cannot resolve CID hash: {hex_key[:16]}...")

def _ipfs_cat_range(self, cid: str, offset: int, length: int) -> bytes:
        """Fetch a byte range from IPFS. Falls back to full fetch + slice."""
        # IPFS HTTP API doesn't support byte ranges natively;
        # fetch the full chunk and slice (chunks are ≤4MB so this is fast)
        data = self._ipfs_cat(cid)
        if offset + length > len(data):
            raise ValueError(
                f"Offset {offset}+{length} exceeds chunk size {len(data)}"
            )
        return data[offset:offset + length]

def _submit_proof(self, challenge_id: int, proof_bytes: bytes) -> str:
        """Submit proof transaction to the contract."""
        proof_b32 = proof_bytes[:32].ljust(32, b'\x00')

        with self._nonce_lock:
            tx_hash = self.contract.functions.submitProof(
                challenge_id,
                proof_b32,
            ).transact({
                "from": self.wallet,
                "gas": 200000,
            })
            receipt = self.w3.eth.wait_for_transaction_receipt(tx_hash, timeout=30)

        if receipt["status"] != 1:
            raise RuntimeError(f"submitProof tx reverted: {tx_hash.hex()}")
        return tx_hash.hex()

def _try_fetch_from_peers(self, challenge_id: int, chunk_cid_hash: bytes,
                              offset: int, chunk_size: int):
        """Try to fetch chunk from other IPFS nodes as fallback."""
        self.log.info("  Attempting peer fallback for challenge %d", challenge_id)
        try:
            cid = self._resolve_cid(chunk_cid_hash)
        except ValueError:
            self.log.error("  Cannot resolve CID — accepting penalty")
            return

        for name, api in IPFS_NODES.items():
            if name == self.node_name:
                continue
            try:
                r = requests.post(f"{api}/cat", params={"arg": cid}, timeout=15)
                if r.status_code == 200:
                    chunk_data = r.content
                    if offset + 32 <= len(chunk_data):
                        proof_bytes = chunk_data[offset:offset + 32]
                        tx_hash = self._submit_proof(challenge_id, proof_bytes)
                        self.log.info("  Peer fallback via %s: tx=%s", name, tx_hash[:16])
                        return
            except Exception:
                continue

        self.log.error("  All peer attempts failed — accepting RST penalty")

def run(self, once: bool = False):
        """Main event loop."""
        self.log.info("Starting prover loop (poll every %ds)...", POLL_INTERVAL)

        def _shutdown(sig, frame):
            self.log.info("Shutdown signal received")
            self._running = False

        signal.signal(signal.SIGTERM, _shutdown)
        signal.signal(signal.SIGINT, _shutdown)

        while self._running:
            try:
                self.poll_challenges()
            except Exception as e:
                self.log.error("Poll error: %s", e, exc_info=True)

            if once:
                break
            time.sleep(POLL_INTERVAL)

        self.log.info("Prover stopped")

def get_base_budget(role: str) -> int:
    """Get base ECT budget for an agent role."""
