def calculate_budget(base: int, quality_score: int) -> int:
    """Apply performance bonus or penalty to base budget.

    Args:
        base: Base ECT amount for role tier
        quality_score: 0-100 quality score from DecisionQuality contract

    Returns: Adjusted ECT amount
    """
    if quality_score >= BONUS_THRESHOLD:
        # Scale bonus linearly from 0% at threshold to 50% at score=100
        bonus_pct = ((quality_score - BONUS_THRESHOLD) / (100 - BONUS_THRESHOLD)) * BONUS_MULTIPLIER
        return int(base * (1 + bonus_pct))
    elif quality_score < PENALTY_THRESHOLD and quality_score > 0:
        return int(base * (1 - PENALTY_MULTIPLIER))
    return base

