def test_cannot_verify_twice(self, contract, wallet, w3):
        """After verification resolves a challenge, second verify should revert."""
        info = self._issue_test_challenge(contract, wallet, w3)
        c_id = info["challenge_id"]

        proof_data = b'\xab' * 32
        tx = contract.functions.submitProof(c_id, proof_data).transact({
            "from": wallet, "gas": 200000,
        })
        w3.eth.wait_for_transaction_receipt(tx, timeout=30)

        # Verify (resolves the challenge)
        tx = contract.functions.verifyProof(c_id, proof_data).transact({
            "from": wallet, "gas": 200000,
        })
        w3.eth.wait_for_transaction_receipt(tx, timeout=30)

        # Second verify should revert — tx will be mined but receipt.status == 0
        tx2 = contract.functions.verifyProof(c_id, proof_data).transact({
            "from": wallet, "gas": 200000,
        })
        receipt2 = w3.eth.wait_for_transaction_receipt(tx2, timeout=30)
        assert receipt2["status"] == 0, "Second verifyProof should revert"

