        self,
        chunk_cids: List[str],
        chunk_nodes: List[List[str]],
        min_chunks: int,
    ) -> List[Tuple[int, bytes]]:
        """Fetch chunks from IPFS in parallel with early exit.

        Returns list of (chunk_index, chunk_blob) tuples.
        Stops fetching once min_chunks are received.
        """
        results = []
        fetch_order = list(range(len(chunk_cids)))

        # Prioritize data chunks (0..k-1) over parity chunks
        # This enables the fast decode path more often
        fetch_order.sort(key=lambda i: (0 if i < DATA_CHUNKS else 1, i))

        def _fetch_one(idx: int) -> Tuple[int, bytes]:
            cid = chunk_cids[idx]
            nodes = chunk_nodes[idx] if idx < len(chunk_nodes) else self._healthy_nodes
            for node in nodes:
                if node not in self._healthy_nodes:
                    continue
                try:
                    data = self._ipfs_cat(cid, node)
                    return (idx, data)
                except Exception:
                    continue
            # Try all healthy nodes as fallback (IPFS content routing)
            for node in self._healthy_nodes:
                try:
                    data = self._ipfs_cat(cid, node)
                    return (idx, data)
                except Exception:
                    continue
            raise RuntimeError(f"Chunk {idx} ({cid[:16]}...) unreachable on all nodes")

        with ThreadPoolExecutor(max_workers=min(8, len(chunk_cids))) as executor:
            futures = {}
            for idx in fetch_order:
                if len(results) >= min_chunks:
                    break
                futures[executor.submit(_fetch_one, idx)] = idx

            for future in as_completed(futures):
