        result = storage.upload_distributed(Path(sys.argv[2]))
        print(json.dumps(result, indent=2))

    elif cmd == "download" and len(sys.argv) >= 4:
        result = storage.download_distributed(sys.argv[2], Path(sys.argv[3]))
