def _gf_mul(a: int, b: int) -> int:
    """GF(2^8) multiplication via lookup."""
    return int(_MUL_TABLE[a][b])

def _gf_inv(a: int) -> int:
    """GF(2^8) multiplicative inverse."""
    if a == 0:
        raise ZeroDivisionError("No inverse for 0 in GF(2^8)")
    return int(_EXP[255 - int(_LOG[a])])

def _gf_div(a: int, b: int) -> int:
    """GF(2^8) division: a / b."""
    if b == 0:
        raise ZeroDivisionError("Division by zero in GF(2^8)")
    if a == 0:
        return 0
    return int(_EXP[(int(_LOG[a]) - int(_LOG[b])) % 255])

def _gf_mat_vec_mul(matrix: np.ndarray, data_columns: np.ndarray) -> np.ndarray:
    """Multiply matrix (m×k, GF(2^8)) by data_columns (k×N bytes).

    Returns m×N result. Uses block processing with np.take for
    cache-friendly vectorized GF(2^8) multiplication.
    """
    m, k = matrix.shape
    N = data_columns.shape[1]
    result = np.zeros((m, N), dtype=np.uint8)

    for start in range(0, N, _GF_BLOCK):
        end = min(start + _GF_BLOCK, N)
        block = data_columns[:, start:end]
        for i in range(m):
            acc = np.zeros(end - start, dtype=np.uint8)
            for j in range(k):
                coeff = int(matrix[i, j])
                if coeff == 0:
                    continue
                if coeff == 1:
                    np.bitwise_xor(acc, block[j], out=acc)
                else:
                    np.bitwise_xor(acc, np.take(_MUL_TABLE[coeff], block[j]), out=acc)
            result[i, start:end] = acc

    return result

def verify_chunk(chunk_blob: bytes) -> bool:
    """Quick validation that a chunk blob has valid structure."""
    if len(chunk_blob) < OVERHEAD:
        return False
    try:
        meta = ChunkMeta.decode_header(chunk_blob[:OVERHEAD])
        return (
            meta.chunk_id < meta.total_chunks
            and meta.data_chunks > 0
            and meta.total_chunks > meta.data_chunks
            and meta.chunk_data_len == len(chunk_blob) - OVERHEAD
        )
    except Exception:
        return False

