def _transact_with_retry(self, tx_func, description: str) -> Optional[str]:
        """Execute a contract transaction with nonce-conflict retry.

        Args:
            tx_func: Bound contract function (e.g. contract.functions.spendECT(...))
            description: Human-readable description for logging

        Returns: tx hash hex string, or None on failure
        """
        for attempt in range(1, MAX_RETRIES + 1):
            with self._nonce_lock:
                try:
                    tx_hash = tx_func.transact({
                        "from": self.wallet,
                        "gas": 200000,
                    })
                    receipt = self.w3.eth.wait_for_transaction_receipt(
                        tx_hash, timeout=30,
                    )
                    if receipt["status"] == 1:
                        hex_hash = tx_hash.hex()
                        self.log.info(
                            "%s OK: tx=%s gas=%d",
                            description, hex_hash[:16], receipt["gasUsed"],
                        )
                        return hex_hash
                    else:
                        self.log.error("%s reverted on attempt %d", description, attempt)
                except Exception as exc:
                    err_str = str(exc).lower()
                    if "nonce" in err_str and attempt < MAX_RETRIES:
                        self.log.warning(
                            "%s nonce conflict (attempt %d/%d), retrying...",
                            description, attempt, MAX_RETRIES,
                        )
                        time.sleep(RETRY_DELAY * attempt)
                        continue
                    self.log.error("%s failed: %s", description, exc)
                    return None
        return None

def mint_daily(self, amount: int) -> Optional[str]:
        """Mint daily ECT allocation (admin only, synchronous)."""
        return self._transact_with_retry(
            self.contract.functions.mintDailyECT(
                self.agent_address, amount,
            ),
            f"mintDailyECT({self.agent_id}, {amount})",
        )

async def async_spend(self, amount: int, task_id: str) -> Optional[str]:
        """Async ECT spend."""
        loop = asyncio.get_running_loop()
        return await loop.run_in_executor(
            None, partial(self.spend, amount, task_id),
        )

async def async_mint_daily(self, amount: int) -> Optional[str]:
        """Async daily mint."""
        loop = asyncio.get_running_loop()
        return await loop.run_in_executor(
            None, partial(self.mint_daily, amount),
        )

