contract PidRegistry {
    mapping(address => uint256) public pids;
    uint256 private nextPid = 1;

    event PidAssigned(address indexed node, uint256 pid);

    function getPid(address node) external returns (uint256) {
        if (pids[node] == 0) {
            pids[node] = nextPid++;
            emit PidAssigned(node, pids[node]);
        }
        return pids[node];
    }

    function viewPid(address node) external view returns (uint256) {
        return pids[node];
    }
}

contract ServiceRegistry {
    struct ServiceInfo {
        address nodeWallet;
        bool active;
        bytes32 configHash;
        uint256 timestamp;
    }

    mapping(bytes32 => ServiceInfo) public services;

    event ServiceRegistered(string name, address node, bytes32 configHash, uint256 timestamp);
    event ServiceDeregistered(string name, address node, uint256 timestamp);

    function register(string calldata name, bytes32 configHash) external {
        bytes32 key = keccak256(abi.encodePacked(name, msg.sender));
        services[key] = ServiceInfo(msg.sender, true, configHash, block.timestamp);
        emit ServiceRegistered(name, msg.sender, configHash, block.timestamp);
    }

    function deregister(string calldata name) external {
        bytes32 key = keccak256(abi.encodePacked(name, msg.sender));
        require(services[key].active, "Service not active");
        services[key].active = false;
        emit ServiceDeregistered(name, msg.sender, block.timestamp);
    }

    function getService(string calldata name, address node) external view returns (bool active, bytes32 configHash, uint256 timestamp) {
        bytes32 key = keccak256(abi.encodePacked(name, node));
        ServiceInfo memory s = services[key];
        return (s.active, s.configHash, s.timestamp);
    }
}

contract ResourceManager {
    struct Node {
        address wallet;
        string hostname;
        uint256 cpuCores;
        uint256 memoryGB;
        uint256 storageGB;
        uint256 aiTops;
        bool active;
        uint256 registeredAt;
    }

    mapping(address => Node) public nodes;
    address[] public nodeAddresses;

    event NodeRegistered(address indexed wallet, string hostname, uint256 timestamp);
    event ResourcesAllocated(address indexed node, address indexed requester, uint256 amount);

    function registerNode(
        string memory hostname,
        uint256 cpuCores,
        uint256 memoryGB,
        uint256 storageGB,
        uint256 aiTops
    ) public {
        require(nodes[msg.sender].wallet == address(0), "Node already registered");

        nodes[msg.sender] = Node({
            wallet: msg.sender,
            hostname: hostname,
            cpuCores: cpuCores,
            memoryGB: memoryGB,
            storageGB: storageGB,
            aiTops: aiTops,
            active: true,
            registeredAt: block.timestamp
        });

        nodeAddresses.push(msg.sender);
        emit NodeRegistered(msg.sender, hostname, block.timestamp);
    }

    function getNode(address wallet) public view returns (
        string memory hostname,
        uint256 cpuCores,
        uint256 memoryGB,
        uint256 storageGB,
        uint256 aiTops,
        bool active
    ) {
        Node memory node = nodes[wallet];
        require(node.wallet != address(0), "Node not found");
        return (node.hostname, node.cpuCores, node.memoryGB, node.storageGB, node.aiTops, node.active);
    }

    function getNodeCount() public view returns (uint256) {
        return nodeAddresses.length;
    }

    function getAllNodes() public view returns (address[] memory) {
        return nodeAddresses;
    }
}

contract ReasoningLedger {
    struct ReasoningEntry {
        address agent;
        uint256 timestamp;
        string decision;
        string reasoning;
        bytes32 entryHash;
    }

    ReasoningEntry[] public entries;
    mapping(address => uint256[]) public agentHistory;

    event ReasoningLogged(
        uint256 indexed entryId,
        address indexed agent,
        bytes32 entryHash,
        uint256 timestamp
    );

    function logReasoning(
        string memory decision,
        string memory reasoning
    ) public returns (uint256) {
        bytes32 entryHash = keccak256(abi.encodePacked(
            msg.sender,
            block.timestamp,
            decision,
            reasoning
        ));

        ReasoningEntry memory entry = ReasoningEntry({
            agent: msg.sender,
            timestamp: block.timestamp,
            decision: decision,
            reasoning: reasoning,
            entryHash: entryHash
        });

        entries.push(entry);
        uint256 entryId = entries.length - 1;
        agentHistory[msg.sender].push(entryId);

        emit ReasoningLogged(entryId, msg.sender, entryHash, block.timestamp);
        return entryId;
    }

    function getEntry(uint256 entryId) public view returns (
        address agent,
        uint256 timestamp,
        string memory decision,
        string memory reasoning,
        bytes32 entryHash
    ) {
        require(entryId < entries.length, "Entry does not exist");
        ReasoningEntry memory entry = entries[entryId];
        return (entry.agent, entry.timestamp, entry.decision, entry.reasoning, entry.entryHash);
    }

    function getAgentHistory(address agent) public view returns (uint256[] memory) {
        return agentHistory[agent];
    }

    function getEntryCount() public view returns (uint256) {
        return entries.length;
    }
}

contract MeshRegistry {
    struct MeshPeer {
        address wallet;
        string enodeUrl;
        string wgPublicKey;
        string meshIP;
        bool active;
        uint256 timestamp;
    }

    mapping(address => MeshPeer) public peers;
    address[] public peerList;

    event PeerRegistered(address wallet, string meshIP, uint256 timestamp);

    function registerPeer(string calldata enodeUrl, string calldata wgPubKey, string calldata meshIP) external {
        if (!peers[msg.sender].active) {
            peerList.push(msg.sender);
        }
        peers[msg.sender] = MeshPeer(msg.sender, enodeUrl, wgPubKey, meshIP, true, block.timestamp);
        emit PeerRegistered(msg.sender, meshIP, block.timestamp);
    }

    function getPeerCount() external view returns (uint256) {
        return peerList.length;
    }

    function getPeer(address wallet) external view returns (string memory enodeUrl, string memory wgPubKey, string memory meshIP, bool active) {
        MeshPeer memory peer = peers[wallet];
        return (peer.enodeUrl, peer.wgPublicKey, peer.meshIP, peer.active);
    }

    function getPeerAddress(uint256 index) external view returns (address) {
        require(index < peerList.length, "Index out of bounds");
        return peerList[index];
    }
}

def recall(query: str, n=5, collection='decisions') -> list:
    col = {'decisions': decisions, 'failures': failures,
           'context': context}.get(collection, decisions)
    try:
        results = col.query(query_texts=[query], n_results=n)
        return results['documents'][0] if results['documents'] else []
    except Exception:
        return []

def seed_from_file(path: str, tag: str):
    with open(path) as f:
        content = f.read()
    chunks = []
    for i in range(0, len(content), 400):
        chunks.append(content[i:i+500])
    for i, chunk in enumerate(chunks):
        remember(chunk, {'source': path, 'chunk': str(i), 'tag': tag}, 'context')
    print(f'Seeded {len(chunks)} chunks from {path}')

def get_tracked(conn: sqlite3.Connection, file_path: str):
    row = conn.execute(
        "SELECT file_hash, chunks_created FROM indexed_files WHERE file_path=?",
        (file_path,)
    ).fetchone()
    return row  # (hash, chunks) or None

def sha256_file(path: Path) -> str:
    h = hashlib.sha256()
    with open(path, "rb") as f:
        for block in iter(lambda: f.read(65536), b""):
            h.update(block)
    return h.hexdigest()

def chunk_id(file_path: str, chunk_identifier: str) -> str:
    raw = f"{file_path}:{chunk_identifier}"
    return hashlib.sha256(raw.encode()).hexdigest()[:16]

def read_file(path: Path) -> str | None:
    """Read text file, trying utf-8 then latin-1. Returns None on failure."""
    for enc in ("utf-8", "latin-1"):
        try:
            return path.read_text(encoding=enc)
        except (UnicodeDecodeError, PermissionError):
            continue
    return None

def is_binary(path: Path) -> bool:
    try:
        chunk = path.read_bytes()[:8192]
        return b"\x00" in chunk
    except (PermissionError, OSError):
        return True

def large_file_chunks(text: str) -> list[str]:
    """Split text at character boundaries with overlap for large files."""
    chunks, start = [], 0
    while start < len(text):
        end = start + LARGE_CHUNK_CHARS
        chunks.append(text[start:end])
        start = end - LARGE_OVERLAP_CHARS
        if start >= len(text):
            break
    return chunks

def _load_ts_python():
    try:
        import tree_sitter_python as tsp
        from tree_sitter import Language, Parser
        lang = Language(tsp.language())
        parser = Parser(lang)
        return parser
    except Exception:
        return None

def ts_parser():
    global _TS_PARSER, _TS_TRIED
    if not _TS_TRIED:
        _TS_PARSER = _load_ts_python()
        _TS_TRIED = True
    return _TS_PARSER

def _node_name(node, source: bytes) -> str:
    for child in node.children:
        if child.type == "identifier":
            return _node_text(child, source)
    return ""

def _node_docstring(node, source: bytes) -> str:
    """Extract the first string literal from the function/class body."""
    body = next((c for c in node.children if c.type == "block"), None)
    if not body:
        return ""
    for stmt in body.children:
        if stmt.type == "expression_statement":
            for s in stmt.children:
                if s.type == "string":
                    return _node_text(s, source)
    return ""

