def check_command_safety(command: str) -> dict:
    """Assess whether a shell command is safe to execute autonomously.

    Returns:
        {"safe": True,  "reason": "allowlisted"}
        {"safe": False, "reason": "<blocklist|needs_approval> — <detail>"}

    Logic:
        1. Blocklist substring scan (hard block).
        2. First token against allowlist (unknown → needs human approval).
        Special: intent_registry.yaml — permits status-field-only sed patterns.
    """
    cmd = command.strip()
    if not cmd:
        return {"safe": True, "reason": "empty command"}

    # 1. Blocklist — any substring is a hard block
    for blocked in COMMAND_BLOCKLIST:
        if blocked in cmd:
            return {
                "safe":   False,
                "reason": f"blocklist — matched: {blocked!r}",
            }

    # 2. Special case: intent_registry.yaml status-only edits are permitted
    if "intent_registry.yaml" in cmd:
        # Allow if it's a targeted status field update (sed -i 's/status: .../status: .../g')
        if re.search(r"sed.*status:.*intent_registry\.yaml", cmd):
            return {"safe": True, "reason": "intent_registry status update (allowed)"}
        return {
            "safe":   False,
            "reason": "needs_approval — intent_registry.yaml modifications require review",
        }

    # 3. Allowlist — unknown first token → needs approval
    parts = cmd.split()
    first = parts[0] if parts else ""
    if first and first not in COMMAND_ALLOWLIST:
        return {
            "safe":   False,
            "reason": f"needs_approval — {first!r} not in command allowlist",
        }

    return {"safe": True, "reason": "allowlisted"}

def check_change_size(plan: dict) -> dict:
    """Check whether a plan's change volume is within safety limits.

    Returns:
        {"within_limits": True,  "needs_approval": False, "reason": ""}
        {"within_limits": True,  "needs_approval": True,  "reason": "<soft limit detail>"}
        {"within_limits": False, "needs_approval": False, "reason": "<hard limit detail>"}
    """
    steps          = plan.get("steps", []) or []
    files_modified = plan.get("files_modified", []) or []
    files_created  = plan.get("files_created", []) or []

    total_added   = sum(s.get("lines_added_estimate", 0)   for s in steps)
    total_deleted = sum(s.get("lines_deleted_estimate", 0) for s in steps)
    num_modified  = len(files_modified)
    num_total     = num_modified + len(files_created)

    # Hard limits (within_limits=False)
    if total_added > MAX_LINES_ADDED:
        return {
            "within_limits":  False,
            "needs_approval": False,
            "reason": f"hard limit: {total_added} lines added (max {MAX_LINES_ADDED})",
        }
    if total_deleted > MAX_LINES_DELETED:
        return {
            "within_limits":  False,
            "needs_approval": False,
            "reason": f"hard limit: {total_deleted} lines deleted (max {MAX_LINES_DELETED})",
        }
    if num_modified > MAX_FILES_MODIFIED:
        return {
            "within_limits":  False,
            "needs_approval": False,
            "reason": f"hard limit: {num_modified} files modified (max {MAX_FILES_MODIFIED})",
        }

    # Soft limits (needs_approval=True)
    if total_added > SOFT_LINES_ADDED:
        return {
            "within_limits":  True,
            "needs_approval": True,
            "reason": f"soft limit: {total_added} lines added (threshold {SOFT_LINES_ADDED})",
        }
    if total_deleted > SOFT_LINES_DELETED:
        return {
            "within_limits":  True,
            "needs_approval": True,
            "reason": f"soft limit: {total_deleted} li

def check_secrets_in_output(text: str) -> bool:
    """Return True if text appears to contain secrets (keys, tokens, passwords)."""
    for detect_re, _, _ in _SECRET_SPECS:
        if detect_re.search(text):
            return True
    return False

def sanitize_for_log(text: str) -> str:
    """Replace any detected secrets in text with '[REDACTED]' before logging."""
    if not text:
        return text
    for _, redact_re, replacement in _SECRET_SPECS:
        text = redact_re.sub(replacement, text)
    return text

def _rec(node: str, service: str, status: str, extra: dict = None) -> dict:
    return {
        "node_name":    node,
        "service_name": service,
        "status":       status,
        "extra_json":   json.dumps(extra or {}),
        "timestamp":    datetime.utcnow().isoformat(),
    }

def _ssh(node: str, command: str) -> Optional[str]:
    """Run command on node via SSH (or locally for nexus-admin).

    Returns stdout strip on success, None if SSH fails or times out.
    """
    ip = NODE_IPS.get(node)
    if ip is None:
        # Local execution
        try:
            r = subprocess.run(
                command, shell=True, capture_output=True, text=True,
                timeout=SSH_TIMEOUT,
            )
            return r.stdout.strip() if r.returncode == 0 else None
        except subprocess.TimeoutExpired:
            return None
        except Exception:
            return None

    full_cmd = f"ssh {SSH_OPTS} mhuraibi@{ip} {shlex.quote(command)}"
    try:
        r = subprocess.run(
            full_cmd, shell=True, capture_output=True, text=True,
            timeout=SSH_TIMEOUT + 5,
        )
        return r.stdout.strip() if r.returncode == 0 else None
    except subprocess.TimeoutExpired:
        log.warning("SSH timeout: %s@%s", node, command[:40])
        return None
    except Exception as e:
        log.warning("SSH error %s: %s", node, e)
        return None

def _ssh_reachable(node: str) -> bool:
    """Quick reachability check (hostname command)."""
    return _ssh(node, "hostname") is not None

def _check_geth(results: list) -> None:
    for node in GETH_NODES:
        if not _ssh_reachable(node):
            results.append(_rec(node, "geth", "unreachable"))
            continue
        raw = _ssh(
            node,
            "sudo geth attach --exec 'admin.peers.length' /opt/nexus/blockchain/geth.ipc 2>/dev/null",
        )
        if raw is None:
            results.append(_rec(node, "geth", "failed", {"reason": "attach failed"}))
            continue
        try:
            peers = int(raw.strip())
        except ValueError:
            results.append(_rec(node, "geth", "failed", {"reason": f"bad output: {raw[:40]}"}))
            continue
        status = "active" if peers >= 2 else "degraded"
        results.append(_rec(node, "geth", status, {"peers": peers}))

def _check_ipfs(results: list) -> None:
    for node in IPFS_NODES:
        if not _ssh_reachable(node):
            results.append(_rec(node, "ipfs", "unreachable"))
            continue
        raw = _ssh(node, "IPFS_PATH=/opt/nexus/ipfs ipfs swarm peers 2>/dev/null | wc -l")
        if raw is None:
            results.append(_rec(node, "ipfs", "failed", {"reason": "command failed"}))
            continue
        try:
            peer_count = int(raw.strip())
        except ValueError:
            results.append(_rec(node, "ipfs", "failed", {"reason": f"bad output: {raw[:40]}"}))
            continue
        status = "failed" if peer_count == 0 else ("degraded" if peer_count < 3 else "active")
        results.append(_rec(node, "ipfs", status, {"peers": peer_count}))

def _check_http(node: str, service: str, url: str,
                down_status: str = "failed") -> dict:
    """Generic HTTP health check."""
    try:
        r = requests.get(url, timeout=HTTP_TIMEOUT)
        status = "active" if r.status_code == 200 else "degraded"
        return _rec(node, service, status, {"http_status": r.status_code})
    except requests.exceptions.Timeout:
        return _rec(node, service, down_status, {"reason": "timeout"})
    except Exception as e:
        return _rec(node, service, down_status, {"reason": str(e)[:80]})

def _check_systemd(results: list) -> None:
    """Per-node systemd service status sweep."""
    checks = {
        "nexus-master":  ["nexus-geth.service", "k3s.service",       "ipfs.service"],
        "nexus-ai":      ["nexus-geth.service", "ipfs.service"],
        "nexus-storage": ["nexus-geth.service", "ipfs.service",       "k3s-agent.service"],
        "nexus-ai2":     ["ollama.service",      "k3s-agent.service"],
        "nexus-admin":   ["nexus-orchestrator.service", "chromadb.service",
                          "ipfs.service", "k3s-agent.service"],
    }
    for node, services in checks.items():
        if not _ssh_reachable(node):
            for svc in services:
                results.append(_rec(node, f"systemd:{svc}", "unreachable"))
            continue
        svc_list = " ".join(services)
        raw = _ssh(node, f"systemctl is-active {svc_list} 2>/dev/null")
        if raw is None:
            for svc in services:
                results.append(_rec(node, f"systemd:{svc}", "unknown"))
            continue
        lines = raw.splitlines()
        for i, svc in enumerate(services):
            if i < len(lines):
                state = lines[i].strip()
                status = "active" if state == "active" else (
                    "inactive" if state in ("inactive", "dead") else "failed"
                )
                results.append(_rec(node, f"systemd:{svc}", status, {"systemd_state": state}))
            else:
                results.append(_rec(node, f"systemd:{svc}", "unknown"))

def update_project_state() -> None:
    """Merge current health snapshot into project_state.json."""
    state_path = Path(PROJECT_STATE)
    try:
        state = json.loads(state_path.read_text())
    except Exception:
        state = {}

    # Build a compact health snapshot
    conn = _get_conn()
    try:
        cur = conn.execute("""
            SELECT node_name, service_name, status, extra_json
            FROM service_health
            WHERE (node_name, service_name, timestamp) IN (
                SELECT node_name, service_name, MAX(timestamp)
                FROM service_health
                GROUP BY node_name, service_name
            )
        """)
        rows = cur.fetchall()
    finally:
        conn.close()

    snapshot: dict = {}
    for node, service, status, extra_json in rows:
        snapshot.setdefault(node, {})[service] = status

    state["health_snapshot"]  = snapshot
    state["health_updated"]   = datetime.utcnow().isoformat()
    state["last_updated"]     = datetime.utcnow().isoformat()
    state["last_updated_by"]  = "health_monitor"

    # Merge inference status from live checks
    if "inference" in state:
        lm = snapshot.get("thinkpad", {}).get("lm_studio")
        ol = snapshot.get("nexus-ai2", {}).get("ollama")
        if lm:
            state["inference"]["tier_1"]["status"] = lm
        if ol:
            state["inference"]["tier_2"]["status"] = ol

    try:
        state_path.write_text(json.dumps(state, indent=2))
        log.debug("project_state.json updated with health snapshot")
    except Exception as e:
        log.error("Failed to update project_state.json: %s", e)

