def execute_on_node(node: str, command: str, timeout: int = 300) -> dict:
    """Run a shell command on the specified node.

    Returns:
        {"stdout": str, "stderr": str, "returncode": int, "node": str, "timed_out": bool}
    """
    ip = NODE_IPS.get(node)

    if ip is None:
        # Local execution
        try:
            r = subprocess.run(
                command, shell=True, capture_output=True, text=True, timeout=timeout
            )
            return {
                "stdout":     r.stdout[:4000],
                "stderr":     r.stderr[:2000],
                "returncode": r.returncode,
                "node":       node,
                "timed_out":  False,
            }
        except subprocess.TimeoutExpired:
            return {"stdout": "", "stderr": "TIMEOUT", "returncode": -1, "node": node, "timed_out": True}
        except Exception as e:
            return {"stdout": "", "stderr": str(e), "returncode": -1, "node": node, "timed_out": False}
    else:
        # Remote execution via SSH
        ssh_cmd = [
            "ssh",
            "-o", "ConnectTimeout=10",
            "-o", "StrictHostKeyChecking=no",
            "-o", "BatchMode=yes",
            f"mhuraibi@{ip}",
            command,
        ]
        try:
            r = subprocess.run(
                ssh_cmd, capture_output=True, text=True, timeout=timeout
            )
            return {
                "stdout":     r.stdout[:4000],
                "stderr":     r.stderr[:2000],
                "returncode": r.returncode,
                "node":       node,
                "timed_out":  False,
            }
        except subprocess.TimeoutExpired:
            return {"stdout": "", "stderr": "SSH TIMEOUT", "returncode": -1, "node": node, "timed_out": True}
        except Exception as e:
            return {"stdout": "", "stderr": str(e), "returncode": -1, "node": node, "timed_out": False}

def rollback_plan(plan: dict, backup_dir: str) -> None:
    """Restore backed-up files and remove any files created by the plan."""
    files_created = plan.get("files_created", []) or []

    # Remove files the plan created
    for fp in files_created:
        if os.path.exists(fp):
            try:
                os.remove(fp)
                log.info("Rollback: removed created file %s", fp)
            except Exception as e:
                log.warning("Rollback: could not remove %s: %s", fp, e)

    # Restore backed-up files via manifest
    manifest_path = os.path.join(backup_dir, "manifest.json")
    if not os.path.isfile(manifest_path):
        return

    with open(manifest_path) as f:
        manifest = json.load(f)

    for backup_name, original_path in manifest.items():
        backup_path = os.path.join(backup_dir, backup_name)
        if not os.path.isfile(backup_path):
            log.warning("Rollback: backup file missing: %s", backup_path)
            continue
        try:
            Path(original_path).parent.mkdir(parents=True, exist_ok=True)
            subprocess.run(["cp", "-p", backup_path, original_path], check=True, capture_output=True)
            log.info("Rollback: restored %s", original_path)
        except Exception as e:
            log.warning("Rollback: could not restore %s: %s", original_path, e)

def _handle_approve(intent_id, params, raw) -> str:
    if intent_id == "all":
        return _approve_all()

    if not intent_id:
        return "Which intent should I approve? Try `approve <id>`."

    try:
        from planning_engine import (
            load_intent_registry, update_intent_autonomous, update_intent_status,
        )
        from intent_parser import set_context

        intents    = load_intent_registry()
        intent_map = {i["id"]: i for i in intents}

        if intent_id not in intent_map:
            return f"⚠️ Intent `{intent_id}` not found."

        intent = intent_map[intent_id]
        ok     = update_intent_autonomous(intent_id, True)

        # If blocked or failed, reset to pending so orchestrator can pick it up
        if intent.get("status") in ("blocked", "failed"):
            update_intent_status(intent_id, "pending")
            log.info("_handle_approve: reset %s from %s → pending", intent_id, intent.get("status"))

        set_context(intent_id=intent_id, approval_id=intent_id)

        if ok:
            return (
                f"✅ Approved `{intent_id}` — {intent.get('title', '')}\n"
                "I'll pick it up next cycle."
            )
        return f"⚠️ `{intent_id}` is already autonomous or the field is missing."
    except Exception as e:
        log.error("_handle_approve: %s", e)
        return f"⚠️ Approve failed: {e}"

def _approve_all() -> str:
