                        if entry.get("intent_id") == intent_id and not entry.get("success"):
                            error_info = entry  # keep last failure
                    except Exception:
                        pass
        except FileNotFoundError:
            pass

        if error_info:
            error_msg   = error_info.get("error", "Unknown error")
            steps_done  = error_info.

