def mark_done(self, task: TaskState):
        """Update the queue entry with final status."""
        data = self._load()
        for task_data in data.get("tasks", []):
            if task_data.get("id") == task.task_id or (
                task_data.get("description") == task.description
                and task_data.get("status") == "in_progress"
            ):
                task_data["status"] = task.status.value
                task_data["completed_at"] = task.completed_at or datetime.now(
                    timezone.utc
                ).isoformat()
                task_data["branch_name"] = task.branch_name
                task_data["error"] = task.error
                break
        self._save(data)

def add(self, description: str, task_id: Optional[str] = None) -> str:
        """Add a new task to the queue. Returns task_id."""
        data = self._load()
        tid = task_id or hashlib.sha256(
            (description + datetime.now(timezone.utc).isoformat()).encode()
        ).hexdigest()[:12]
        data.setdefault("tasks", []).append(
            {
                "id": tid,
                "description": description,
                "status": "queued",
                "created_at": datetime.now(timezone.utc).isoformat(),
            }
        )
        self._save(data)
        return tid

def skip(self, name: str, reason: str):
        self.results.append((name, None, reason))
        print(f"  [\033[33mSKIP\033[0m] {name}  ({reason})")

def __init__(self):
        self._health_cache: dict[str, tuple[bool, float]] = {}
        self._health_ttl = 30.0  # Cache health checks for 30 seconds
        self._build_agent_index()

def _build_agent_index(self):
        """Build reverse index: agent_id → tier_name."""
        self._agent_to_tier: dict[str, str] = {}
        self._task_to_tier: dict[str, str] = {}

        for tier_name, config in TIERS.items():
            for agent_id in config.agents:
                self._agent_to_tier[agent_id] = tier_name
            for task_type in config.task_types:
                self._task_to_tier[task_type] = tier_name

def get_status(self) -> dict:
        """Return current router status for diagnostics."""
        status = {}
        for tier_name, config in TIERS.items():
            cached = self._health_cache.get(config.endpoint)
            status[tier_name] = {
                "endpoint": config.endpoint,
                "model": config.model,
                "healthy": cached[0] if cached else "unknown",
                "agent_count": len(config.agents),
            }
        return status

async def on_message(self, message: discord.Message) -> None:
        global auto_loop
        if message.author == self.user or message.author.bot:
            return
        if not isinstance(message.channel, discord.TextChannel):
            return
        if message.channel.name != self.channel_name:
            return
        if self.owner_id and message.author.id != self.owner_id:
            return

        # Phase 3: suppress normal routing while safety gate is listening
        if auto_loop and auto_loop.gate_active:
            lower_check = message.content.strip().lower()
            if lower_check in ("approve", "yes", "reject", "no", "cancel", "abort"):
                return

        # --- Phase 2: Queue commands ---
        handled, response = handle_queue_command(message.content, task_queue, auto_loop)
        if handled:
            if response == "__HEALTH_CHECK__":
                from health_monitor import HealthMonitor
                monitor = HealthMonitor(
                    llm_endpoints={
                        "coordinator": "http://10.0.30.3:1234/v1/models",
                        "coder": "http://10.0.30.2:1234/v1/models",
                    },
                )
                hresult = await monitor.check_all()
                response = monitor.format_report(hresult)
            if response:
                await message.channel.send(response)
            return

        # --- Phase 2: Start/stop autonomous mode ---
        _lower = message.content.strip().lower()
        if _lower in ("go", "start", "start autonomous", "autonomous"):
            channel = message.channel
            if auto_loop and auto_loop.is_running:
                await channel.send("Already running. Say `pause` to stop.")
            else:
                auto_loop = AutonomousLoop(
                    queue=task_queue,
                    channel=channel,
                    execute_fn=execute_task_from_queue,
                    decompose_fn=decompose_ta

async def on_raw_reaction_add(self, payload: RawReactionActionEvent) -> None:
        if payload.user_id == self.user.id:
            return
        if self.owner_id and payload.user_id != self.owner_id:
            return
        if not self.active_task:
            return
        if self.active_task.status != "awaiting_approval":
            return
        if payload.message_id != self.active_task.plan_msg_id:
            return

        emoji = str(payload.emoji)
        if emoji == "✅":
            asyncio.create_task(self._execute())
        elif emoji == "❌":
            await self.channel.send("🔧 ❌ Plan rejected via reaction. No files were modified.")
            self.active_task.status = "failed"
            self.active_task = None

def _read_file(self, path_str: str) -> Optional[str]:
        """
        Read a file under /opt/nexus/. Returns None on any error or policy violation.
        Truncates at MAX_FILE_SIZE chars.
        """
        path = self._resolve_path(path_str)
        if path is None:
            return None
        if not path.is_file():
            return None
        try:
            content = path.read_text(errors="replace")
        except OSError as exc:
            log.warning("Cannot read %s: %s", path, exc)
            return None
        if len(content) > MAX_FILE_SIZE:
            content = content[:MAX_FILE_SIZE] + "\n[TRUNCATED]"
        return content

def _resolve_path(self, path_str: str) -> Optional[Path]:
        """
        Resolve path to an absolute Path under NEXUS_ROOT.
        Returns None if the path is outside NEXUS_ROOT or matches a protected pattern.
        """
        try:
            path = Path(path_str).expanduser().resolve()
        except Exception:
            return None

        try:
            path.relative_to(NEXUS_ROOT)
        except ValueError:
            log.warning("Path outside NEXUS_ROOT denied: %s", path_str)
            return None

        path_lower = str(path).lower()
        name_lower = path.name.lower()
        for protected in PROTECTED_PATHS:
            if protected in path_lower or protected in name_lower:
                log.warning("Protected path denied (%r): %s", protected, path_str)
                return None

        return path

def _format_file_context(self, files_read: Dict[str, str]) -> str:
        """Format cached file contents for LLM context."""
        if not files_read:
            return "(no files read yet)"
        blocks = [f"=== {path} ===\n{content}" for path, content in files_read.items()]
        return "\n\n".join(blocks)

def _parse_json(self, text: str) -> Optional[dict]:
        """Extract the first JSON object from an LLM response."""
        try:
            return json.loads(text.strip())
        except json.JSONDecodeError:
            pass
        m = re.search(r"```(?:json)?\s*\n(\{.*?\})\s*```", text, re.DOTALL)
        if m:
            try:
                return json.loads(m.group(1))
            except json.JSONDecodeError:
                pass
        start, end = text.find("{"), text.rfind("}")
        if start != -1 and end > start:
            try:
                return json.loads(text[start:end + 1])
            except json.JSONDecodeError:
                pass
        return None

def __init__(self, path: str = DEFAULT_QUEUE_PATH):
        self._path = path
        self._lock = threading.Lock()
        # Ensure file exists
        if not os.path.exists(path):
            self._save({"tasks": []})

def _load(self) -> dict:
        try:
            with open(self._path, "r") as f:
                data = yaml.safe_load(f)
            if not isinstance(data, dict) or "tasks" not in data:
                return {"tasks": []}
            return data
        except (yaml.YAMLError, OSError) as e:
            log.error("Failed to load task queue: %s", e)
            return {"tasks": []}

def _save(self, data: dict) -> None:
        tmp = self._path + ".tmp"
        try:
            with open(tmp, "w") as f:
                yaml.dump(data, f, default_flow_style=False, sort_keys=False, width=120)
            os.replace(tmp, self._path)
        except OSError as e:
            log.error("Failed to save task queue: %s", e)

def _find(self, data: dict, task_id: str) -> Optional[dict]:
        for t in data["tasks"]:
            if t["id"] == task_id:
                return t
        return None

def list_all(self) -> list[dict]:
        with self._lock:
            data = self._load()
            return deepcopy(data["tasks"])

def count_by_status(self) -> dict[str, int]:
        with self._lock:
            data = self._load()
            counts: dict[str, int] = {}
            for t in data["tasks"]:
                s = t.get("status", "pending")
                counts[s] = counts.get(s, 0) + 1
            return counts

def queue_depth(self) -> int:
        with self._lock:
            data = self._load()
            return sum(1 for t in data["tasks"] if t["status"] == "pending")

def _deps_satisfied(self, task: dict, all_tasks: list[dict]) -> bool:
        """Check if all depends_on tasks are in 'done' status."""
        deps = task.get("depends_on", [])
        if not deps:
            return True
        status_map = {t["id"]: t["status"] for t in all_tasks}
        return all(status_map.get(dep) == "done" for dep in deps)

def pop_next(self) -> Optional[dict]:
        """Get the highest-priority pending task whose dependencies are satisfied.
        Atomically transitions it to 'analyzing'. Returns None if queue empty."""
        with self._lock:
            data = self._load()
            candidates = [
                t for t in data["tasks"]
                if t["status"] == "pending" and self._deps_satisfied(t, data["tasks"])
            ]
            if not candidates:
                return None

            # Sort: P0 first, then by created time (FIFO within same priority)
            candidates.sort(key=lambda t: (
                PRIORITY_ORDER.get(t.get("priority", "P2"), 2),
                t.get("created", ""),
            ))

            chosen = candidates[0]
            # Update in-place in data
            for t in data["tasks"]:
                if t["id"] == chosen["id"]:
                    t["status"] = "analyzing"
                    t["started"] = _now_iso()
                    break

            self._save(data)
            return deepcopy(chosen)

def update_status(
        self,
        task_id: str,
        status: str,
        *,
        error: Optional[str] = None,
        commit_hash: Optional[str] = None,
        blockchain_tx: Optional[str] = None,
        branch: Optional[str] = None,
        diffs: Optional[list[str]] = None,
        lines_added: int = 0,
        lines_removed: int = 0,
        files_changed: int = 0,
    ) -> bool:
        """Update task status and result fields."""
        if status not in VALID_STATUSES:
            log.error("Invalid status: %s", status)
            return False

        with self._lock:
            data = self._load()
            task = self._find(data, task_id)
            if not task:
                log.error("Task %s not found", task_id)
                return False

            task["status"] = status
            if status in ("done", "failed", "cancelled"):
                task["completed"] = _now_iso()
            if branch:
                task["branch"] = branch

            result = task.setdefault("result", {})
            if status == "done":
                result["success"] = True
            elif status == "failed":
                result["success"] = False
            if error is not None:
                result["error"] = error
            if commit_hash:
                result["commit_hash"] = commit_hash
            if blockchain_tx:
                result["blockchain_tx"] = blockchain_tx
            if diffs:
                result["diffs"] = diffs
            if lines_added:
                result["lines_added"] = lines_added
            if lines_removed:
                result["lines_removed"] = lines_removed
            if files_changed:
                result["files_changed"] = files_changed

            self._save(data)
        return True

