            auto_loop.pause()
            return True, "⏸️ Autonomous execution paused. Say `resume` to continue."
        return True, "⏸️ Autonomous loop not active."

    # ── resume ────────────────────────────────────────────────────────────────
    if lower in ("resume", "continue", "

def _cmd_status(queue, auto_loop) -> str:
    if auto_loop:
        return auto_loop.status_text()

    # Fallback if no auto_loop
    counts = queue.count_by_status()
    parts = ["⏹️ **Autonomous loop not active**"]
    parts.append(
        f"📋 Queue: {counts.get('pending', 0)} pending, "
        f"{counts.get('done', 0)} done, {counts.get('failed', 0)} failed"
    )
    return "\n".join(parts)

def _cmd_show_last(queue, n: int) -> str:
    recent = queue.list_recent(n)
    if not recent:
        return "No completed or failed tasks yet."

    lines = [f"📜 **Last {len(recent)} tasks:**\n"]
    for t in recent:
        tid = t["id"]
        desc = t["description"][:45]
        result = t.get("result", {})
        fc = result.get("files_changed", 0)
        la = result.get("lines_added", 0)
        lr = result.get("lines_removed", 0)

        if t["status"] == "done":
            lines.append(f"✅ `{tid}`: {desc} ({fc} files, +{la}/-{lr})")
        else:
            err = (result.get("error") or "unknown")[:35]
            lines.append(f"❌ `{tid}`: {desc} (FAILED: {err})")

    return "\n".join(lines)

def _cmd_add_task(queue, description: str, priority: str = "P2") -> str:
    # Infer risk from description keywords
    risk = "low"
    lower_desc = description.lower()
    if any(w in lower_desc for w in ["deploy", "contract", "blockchain", "delete", "remove", "migration"]):
        risk = "high"
    elif any(w in lower_desc for w in ["refactor", "rewrite", "restructure", "security"]):
        risk = "medium"

    tid = queue.add(description, priority=priority, risk=risk)
    depth = queue.queue_depth()
    return (
        f"📝 Added `{tid}` [{priority}/{risk}]\n"
        f"_{description}_\n"
        f"Queue depth: {depth}"
    )

def _cmd_focus(queue, auto_loop, task_id: str) -> str:
    task = queue.get(task_id)
    if not task:
        return f"⚠️ Task `{task_id}` not found."
    if task["status"] != "pending":
        return f"⚠️ Task `{task_id}` is `{task['status']}`, not pending."

    if auto_loop:
        auto_loop.focus(task_id)
    else:
        queue.focus(task_id)

    return f"📌 Focused on `{task_id}` — it will be picked up next."

def _cmd_remove(queue, task_id: str) -> str:
    task = queue.get(task_id)
    if not task:
        return f"⚠️ Task `{task_id}` not found."

    if queue.remove(task_id):
        return f"🗑️ Removed `{task_id}`."
    else:
        return f"⚠️ Cannot remove `{task_id}` — status is `{task['status']}`."

def _cmd_summary(queue) -> str:
    stats = queue.recent_stats(10)
    if stats["total"] == 0:
        return "No completed tasks to summarize yet."

    lines = [f"📊 **Summary** (last {stats['total']} tasks)\n"]
    lines.append(
        f"Success rate: {stats['success']}/{stats['total']} ({stats['rate']:.0f}%)"
    )
    lines.append(
        f"Total changes: +{stats['lines_added']}/-{stats['lines_removed']} "
        f"across {stats['files_changed']} files"
    )

    pending_count = queue.queue_depth()
    lines.append(f"Queue depth: {pending_count} pending")

    return "\n".join(lines)

async def check_all(self) -> dict:
        """Run all health checks concurrently and return a consolidated report."""
        llm_coros = {
            f"llm_{tier}": self.check_llm(tier, url)
            for tier, url in self.llm_endpoints.items()
        }

        results = await asyncio.gather(
            self.check_disk(),
            self.check_blockchain(),
            *llm_coros.values(),
            return_exceptions=True,
        )

        disk_result = results[0]
        blockchain_result = results[1]
        llm_results = results[2:]

        checks: dict = {}

        checks["disk"] = (
            disk_result
            if isinstance(disk_result, dict)
            else {"ok": False, "free_gb": 0.0, "message": str(disk_result)}
        )

        checks["blockchain"] = (
            blockchain_result
            if isinstance(blockchain_result, dict)
            else {"ok": False, "block_number": 0, "message": str(blockchain_result)}
        )

        for key, result in zip(llm_coros.keys(), llm_results):
            checks[key] = (
                result
                if isinstance(result, dict)
                else {"ok": False, "latency_ms": 0, "message": str(result)}
            )

        healthy = all(v.get("ok", False) for v in checks.values())
        log.info(
            "Health check complete — %s (%d/%d checks ok)",
            "HEALTHY" if healthy else "UNHEALTHY",
            sum(1 for v in checks.values() if v.get("ok")),
            len(checks),
        )

        return {
            "healthy": healthy,
            "checks": checks,
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }

async def check_disk(self) -> dict:
        """Check free disk space under /opt/nexus."""
        try:
            usage = shutil.disk_usage("/opt/nexus")
            free_gb = usage.free / (1024 ** 3)
            ok = free_gb >= DISK_MIN_FREE_GB
            message = (
                f"{free_gb:.1f} GB free"
                if ok
                else f"only {free_gb:.1f} GB free (minimum {DISK_MIN_FREE_GB} GB)"
            )
            log.debug("check_disk: %s", message)
            return {"ok": ok, "free_gb": round(free_gb, 2), "message": message}
        except Exception as exc:
            log.warning("check_disk failed: %s", exc)
            return {"ok": False, "free_gb": 0.0, "message": str(exc)}

async def check_llm(self, tier: str, url: str) -> dict:
        """HTTP GET the LLM models endpoint and record latency."""
        if not HAS_AIOHTTP:
            log.warning("check_llm[%s]: aiohttp not installed", tier)
            return {"ok": False, "latency_ms": 0, "message": "aiohttp not installed"}

        timeout = aiohttp.ClientTimeout(total=LLM_HEALTH_TIMEOUT)
        start = time.monotonic()
        try:
            async with aiohttp.ClientSession(timeout=timeout) as session:
                async with session.get(url) as resp:
                    latency_ms = int((time.monotonic() - start) * 1000)
                    ok = resp.status == 200
                    message = f"{latency_ms}ms" if ok else f"HTTP {resp.status}"
                    log.debug("check_llm[%s]: %s", tier, message)
                    return {"ok": ok, "latency_ms": latency_ms, "message": message}
        except aiohttp.ClientConnectionError as exc:
            latency_ms = int((time.monotonic() - start) * 1000)
            msg = f"Connection refused ({exc.__class__.__name__})"
            log.warning("check_llm[%s]: %s", tier, msg)
            return {"ok": False, "latency_ms": latency_ms, "message": msg}
        except asyncio.TimeoutError:
            latency_ms = int((time.monotonic() - start) * 1000)
            msg = f"Timed out after {LLM_HEALTH_TIMEOUT}s"
            log.warning("check_llm[%s]: %s", tier, msg)
            return {"ok": False, "latency_ms": latency_ms, "message": msg}
        except Exception as exc:
            latency_ms = int((time.monotonic() - start) * 1000)
            msg = str(exc)
            log.warning("check_llm[%s]: %s", tier, msg)
            return {"ok": False, "latency_ms": latency_ms, "message": msg}

async def check_blockchain(self) -> dict:
        """Call eth_blockNumber via JSON-RPC. Falls back to urllib if aiohttp unavailable."""
        payload = {"jsonrpc": "2.0", "method": "eth_blockNumber", "params": [], "id": 1}
        if HAS_AIOHTTP:
            return await self._check_blockchain_aiohttp(payload)
        return await self._check_blockchain_urllib(payload)

async def _check_blockchain_aiohttp(self, payload: dict) -> dict:
        timeout = aiohttp.ClientTimeout(total=LLM_HEALTH_TIMEOUT)
        try:
            async with aiohttp.ClientSession(timeout=timeout) as session:
                async with session.post(self.blockchain_rpc, json=payload) as resp:
                    if resp.status != 200:
                        msg = f"HTTP {resp.status}"
                        log.warning("check_blockchain: %s", msg)
                        return {"ok": False, "block_number": 0, "message": msg}
                    data = await resp.json(content_type=None)
                    return self._parse_block_response(data)
        except aiohttp.ClientConnectionError as exc:
            msg = f"Connection refused ({exc.__class__.__name__})"
            log.warning("check_blockchain: %s", msg)
            return {"ok": False, "block_number": 0, "message": msg}
        except asyncio.TimeoutError:
            msg = f"Timed out after {LLM_HEALTH_TIMEOUT}s"
            log.warning("check_blockchain: %s", msg)
            return {"ok": False, "block_number": 0, "message": msg}
        except Exception as exc:
            msg = str(exc)
            log.warning("check_blockchain: %s", msg)
            return {"ok": False, "block_number": 0, "message": msg}

async def _check_blockchain_urllib(self, payload: dict) -> dict:
        import json
        import urllib.request
        import urllib.error

        body = json.dumps(payload).encode()
        req = urllib.request.Request(
            self.blockchain_rpc,
            data=body,
            headers={"Content-Type": "application/json"},
            method="POST",
        )
        try:
            loop = asyncio.get_event_loop()
            def _do_request():
                with urllib.request.urlopen(req, timeout=LLM_HEALTH_TIMEOUT) as resp:
                    return json.loads(resp.read())
            data = await loop.run_in_executor(None, _do_request)
            return self._parse_block_response(data)
        except urllib.error.URLError as exc:
            msg = str(exc.reason)
            log.warning("check_blockchain(urllib): %s", msg)
            return {"ok": False, "block_number": 0, "message": msg}
        except Exception as exc:
            msg = str(exc)
            log.warning("check_blockchain(urllib): %s", msg)
            return {"ok": False, "block_number": 0, "message": msg}

def _parse_block_response(self, data: dict) -> dict:
        hex_block = data.get("result")
        if hex_block is None:
            error = data.get("error", {}).get("message", "no result field")
            log.warning("check_blockchain: %s", error)
            return {"ok": False, "block_number": 0, "message": error}
        block_number = int(hex_block, 16)
        msg = f"block #{block_number:,}"
        log.debug("check_blockchain: %s", msg)
        return {"ok": True, "block_number": block_number, "message": msg}

def _make_queue(self, tmp_dir):
        path = os.path.join(tmp_dir, "test_queue.yaml")
        return TaskQueue(path), path

async def stop(self):
        """Stop the loop entirely."""
        self._running = False
        if self._task and not self._task.done():
            self._task.cancel()
            try:
                await self._task
            except asyncio.CancelledError:
                pass
        log.info("Autonomous loop stopped")

def focus(self, task_id: str) -> bool:
        """Set a specific task to be picked next."""
        result = self.queue.focus(task_id)
        if result:
            self._focus_task_id = task_id
        return result

async def _post(self, message: str):
        """Post a message to the channel, truncating if needed."""
        if not self.channel:
            log.warning("No channel set, cannot post: %s", message[:100])
            return
        try:
            await self.channel.send(message[:1990])
        except discord.HTTPException as e:
