def format_metrics_report(summary: Optional[dict] = None) -> str:
    """Return a Discord-formatted performance report string."""
    if summary is None:
        summary = get_performance_summary()

    trend = summary.get("trend", "stable")
    trend_emoji = {"improving": "📈", "stable": "➡️", "degrading": "📉"}.get(trend, "➡️")

    lines = [
        f"📈 **Performance Dashboard** (last {summary['window_hours']}h)",
        f"Tasks: {summary['total_tasks']} | Success: {summary['success_rate']}% | Avg: {summary['avg_duration_seconds']}s",
        f"Throughput: {summary['tasks_per_hour']}/hr | Rollbacks: {summary['rollback_count']}",
        f"Trend: {trend_emoji} {trend}",
    ]

    categories = summary.get("failure_categories", {})
    if categories:
        lines.append("")
        lines.append("**Failure Breakdown:**")
        for category, count in sorted(categories.items(), key=lambda x: -x[1]):
            lines.append(f"  • {category}: {count}")

    return "\n".join(lines)

def should_propose_improvement(summary: Optional[dict] = None) -> tuple:
    """Return (True, reason) if metrics suggest a self-improvement task should be created."""
    if summary is None:
        summary = get_performance_summary()

    success_rate = summary.get("success_rate", 0.0)
    if success_rate < 70:
        return (True, f"Low success rate ({success_rate}%)")

    categories = summary.get("failure_categories", {})
    total_failures = sum(categories.values()) if categories else 0
    if total_failures > 0:
        for category, count in categories.items():
            if count / total_failures > 0.30:
                return (True, f"High {category} failure rate")

    trend = summary.get("trend", "stable")
    if trend == "degrading":
        return (True, "Performance degrading")

    return (False, "")

def _truncate(self, text: str, max_chars: int) -> str:
        if len(text) <= max_chars:
            return text
        return text[:max_chars] + "\n\n[... truncated ...]"

def get_core_context(self) -> str:
        """Load AGENTS.md + TOOLS.md + SOUL.md into a single context string."""
        parts = []
        for name in ["AGENTS.md", "TOOLS.md", "SOUL.md"]:
            path = self.root / name
            if path.exists():
                content = self._read_file(path)
                if content:
                    parts.append(f"## {name}\n{content}")
        combined = "\n\n".join(parts)
        return self._truncate(combined, MAX_WORKSPACE_CHARS)

def get_identity(self) -> dict:
        """Load IDENTITY.md and parse key fields."""
        path = self.root / "IDENTITY.md"
        content = self._read_file(path) if path.exists() else ""
        identity = {"name": "Dev Assistant", "emoji": "🔧", "role": "development assistant"}
        for line in content.split("\n"):
            if line.startswith("**Name:**"):
                identity["name"] = line.split(":**", 1)[1].strip()
            elif line.startswith("**Emoji:**"):
                identity["emoji"] = line.split(":**", 1)[1].strip()
            elif line.startswith("**Role:**"):
                identity["role"] = line.split(":**", 1)[1].strip()
        return identity

def get_user_context(self) -> str:
        """Load USER.md for operator preferences."""
        path = self.root / "USER.md"
        if path.exists():
            return self._read_file(path)
        return ""

def find_skills(self, task_description: str) -> list[str]:
        """Find skills whose activation keywords match the task description.
        Returns list of skill directory names."""
        skills_dir = self.root / "skills"
        if not skills_dir.exists():
            return []

        desc_lower = task_description.lower()
        matched = []

        for skill_dir in sorted(skills_dir.iterdir()):
            if not skill_dir.is_dir():
                continue
            skill_file = skill_dir / "SKILL.md"
            if not skill_file.exists():
                continue
            content = self._read_file(skill_file)
            # Parse "When to activate" section for keywords
            activate_match = re.search(
                r"(?:When to activate|Trigger|Keywords).*?:(.+?)(?:\n#|\n\n|\Z)",
                content, re.IGNORECASE | re.DOTALL
            )
            if activate_match:
                keywords_text = activate_match.group(1).lower()
                # Extract quoted keywords or comma-separated words
                keywords = re.findall(r'"([^"]+)"', keywords_text)
                if not keywords:
                    keywords = [k.strip().strip('"\'') for k in keywords_text.split(",")]
                if any(kw.strip() in desc_lower for kw in keywords if kw.strip()):
                    matched.append(skill_dir.name)

        return matched

def get_skill_context(self, skill_names: list[str]) -> str:
        """Load and concatenate skill files for matched skills."""
        parts = []
        for name in skill_names:
            skill_file = self.root / "skills" / name / "SKILL.md"
            if skill_file.exists():
                content = self._read_file(skill_file)
                parts.append(self._truncate(content, MAX_SKILL_CHARS))
        return "\n\n".join(parts)

def build_system_prompt(self, task_description: str = "") -> str:
        """Build the full system prompt from workspace files + matched skills.
        This is the main entry point used by dev_assistant.py."""
        sections = []

        # Core context (AGENTS.md + TOOLS.md + SOUL.md)
        core = self.get_core_context()
        if core:
            sections.append(core)

        # Matched skills
        if task_description:
            matched_skills = self.find_skills(task_description)
            if matched_skills:
                skill_ctx = self.get_skill_context(matched_skills)
                if skill_ctx:
                    sections.append(f"## Active Skills: {', '.join(matched_skills)}\n{skill_ctx}")

        # User preferences
        user_ctx = self.get_user_context()
        if user_ctx:
            sections.append(f"## Operator\n{user_ctx}")

        return "\n\n---\n\n".join(sections)

def _resolve_env_vars(value: str) -> str:
    """Expand ${VAR} placeholders from environment."""
    import re
    def replacer(m):
        return os.environ.get(m.group(1), "")
    return re.sub(r"\$\{(\w+)\}", replacer, value) if isinstance(value, str) else value

async def _handle_ws(self, websocket, path=None):
        """Handle a single WebSocket connection lifecycle."""
        client_info = {"user_id": None, "channel": None, "session_id": None}
        self._clients[websocket] = client_info
        try:
            async for raw_msg in websocket:
                try:
                    msg = json.loads(raw_msg)
                except json.JSONDecodeError:
                    await websocket.send(json.dumps(make_error("Invalid JSON")))
                    continue
                response = await self._route_message(websocket, msg, client_info)
                if response:
                    await websocket.send(json.dumps(response))
        except websockets.exceptions.ConnectionClosed:
            pass
        finally:
            self._clients.pop(websocket, None)
            if client_info.get("role") == "node":
                wallet = client_info.get("wallet", "")
                hostname = client_info.get("hostname", "unknown")
                self.nodes.pop(wallet, None)
                log.info("Node disconnected: %s", hostname)
            else:
                log.debug("Client disconnected: %s", client_info.get("user_id"))

def _find_node(self, target: str):
        """Return (wallet, node_info) matching target by wallet_address or hostname."""
        if target in self.nodes:
            return target, self.nodes[target]
        for wallet, info in self.nodes.items():
            if info["hostname"] == target:
                return wallet, info
        return None, None

async def _broadcast_event(self, event_name: str, data: dict):
        """Send an event to all connected clients."""
        msg = json.dumps(make_event(event_name, data))
        for ws in list(self._clients):
            try:
                await ws.send(msg)
            except Exception:
                pass

