        available = ", ".join(EXTERNAL_TOOLS)
        return {
            "status":  "error",
            "tool":    tool_name,
            "message": f"Unknown tool '{tool_name}'. Available: {available}",
        }

    try:
        url    = _build_url(spec, args)
